import{_ as e,o as t,c as l,a2 as o}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"OLTP、OLAP、ETL、ELT 与 CDC","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"oltp-olap-etl-elt-cdc"},"headers":[],"relativePath":"05-backend-data/notes/cache-messaging-storage/19-oltp-olap-etl-elt-cdc.md","filePath":"05-backend-data/notes/cache-messaging-storage/19-oltp-olap-etl-elt-cdc.md","lastUpdated":1784382745000}'),i={name:"05-backend-data/notes/cache-messaging-storage/19-oltp-olap-etl-elt-cdc.md"};function r(d,a,n,s,c,h){return t(),l("div",null,[...a[0]||(a[0]=[o(`<h1 id="oltp、olap、etl、elt-与-cdc" tabindex="-1">OLTP、OLAP、ETL、ELT 与 CDC <a class="header-anchor" href="#oltp、olap、etl、elt-与-cdc" aria-label="Permalink to &quot;OLTP、OLAP、ETL、ELT 与 CDC&quot;">​</a></h1><p>OLTP 优化小范围事务读写，OLAP 优化大范围扫描聚合。ETL/ELT 描述变换位置，CDC 捕获已提交变化；这些是工作负载和数据流模式，不是互斥产品标签。</p><h2 id="_1-数据流与决策边界" tabindex="-1">1. 数据流与决策边界 <a class="header-anchor" href="#_1-数据流与决策边界" aria-label="Permalink to &quot;1. 数据流与决策边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;源事实/事件&quot;] --&gt; B[&quot;传输与处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;模型/存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;查询与指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;质量、对账与重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>CDC 必须保留源事务顺序、日志位置、主键、操作类型和行版本，才能把 OLTP 变更可靠地投影到 OLAP。快照与增量的交界、更新/删除语义和 schema 演进都需要可验证；只看到目标表“有数据”不能证明没有缺口或重复。</p><h2 id="_2-oltp" tabindex="-1">2. OLTP <a class="header-anchor" href="#_2-oltp" aria-label="Permalink to &quot;2. OLTP&quot;">​</a></h2><p>机制：短事务、点查、小批写、约束和并发控制。</p><p>实际用途：订单、余额、库存事实。</p><p>失败方式：在主库跑无界全表BI。</p><p>验证：事务p99、锁、WAL、连接。</p><p>取舍：强一致写与分析扫描资源冲突。</p><p>OLTP 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_3-olap" tabindex="-1">3. OLAP <a class="header-anchor" href="#_3-olap" aria-label="Permalink to &quot;3. OLAP&quot;">​</a></h2><p>机制：列式读取、压缩、向量化和数据跳过。</p><p>实际用途：跨亿行group/filter分析。</p><p>失败方式：用其替代高并发逐行事务。</p><p>验证：scan bytes、rows/s、query p95。</p><p>取舍：吞吐高但更新/事务语义不同。</p><p>OLAP 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_4-etl" tabindex="-1">4. ETL <a class="header-anchor" href="#_4-etl" aria-label="Permalink to &quot;4. ETL&quot;">​</a></h2><p>机制：抽取后在进入目标前转换。</p><p>实际用途：强清洗、固定仓库模型。</p><p>失败方式：黑盒脚本无原始重放。</p><p>验证：输入输出行数/hash和版本。</p><p>取舍：目标干净但变更需重跑管道。</p><p>ETL 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_5-elt" tabindex="-1">5. ELT <a class="header-anchor" href="#_5-elt" aria-label="Permalink to &quot;5. ELT&quot;">​</a></h2><p>机制：先加载原始/近原始数据，再在目标计算。</p><p>实际用途：云仓库/lake保留可重算历史。</p><p>失败方式：把未治理原始表直接开放。</p><p>验证：分层权限、模型测试和成本。</p><p>取舍：灵活但计算/治理转移到目标。</p><p>ELT 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_6-cdc" tabindex="-1">6. CDC <a class="header-anchor" href="#_6-cdc" aria-label="Permalink to &quot;6. CDC&quot;">​</a></h2><p>机制：读取WAL/binlog变化与事务顺序。</p><p>实际用途：低延迟同步、缓存/搜索/OLAP。</p><p>失败方式：把CDC事件当完整领域语义。</p><p>验证：LSN/offset、snapshot水位、lag。</p><p>取舍：覆盖写者但耦合物理schema。</p><p>CDC 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_7-snapshot" tabindex="-1">7. Snapshot <a class="header-anchor" href="#_7-snapshot" aria-label="Permalink to &quot;7. Snapshot&quot;">​</a></h2><p>机制：提供历史基线并与增量衔接。</p><p>实际用途：首次加载/重建。</p><p>失败方式：snapshot期间直接接当前流量产生缺口。</p><p>验证：一致快照位置与count/hash。</p><p>取舍：成本高但恢复必需。</p><p>Snapshot 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_8-delete-tombstone" tabindex="-1">8. Delete/Tombstone <a class="header-anchor" href="#_8-delete-tombstone" aria-label="Permalink to &quot;8. Delete/Tombstone&quot;">​</a></h2><p>机制：传递源删除和版本。</p><p>实际用途：下游不复活数据。</p><p>失败方式：忽略delete只做upsert。</p><p>验证：源下游删除count和版本。</p><p>取舍：隐私/历史保留需分别定义。</p><p>Delete/Tombstone 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_9-schema-evolution" tabindex="-1">9. Schema evolution <a class="header-anchor" href="#_9-schema-evolution" aria-label="Permalink to &quot;9. Schema evolution&quot;">​</a></h2><p>机制：源列增删/类型变化传播到pipeline。</p><p>实际用途：expand-contract和模型版本。</p><p>失败方式：自动接受破坏类型导致停流。</p><p>验证：兼容检查、DLQ和canary。</p><p>取舍：治理增加发布协调。</p><p>Schema evolution 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_10-watermark" tabindex="-1">10. Watermark <a class="header-anchor" href="#_10-watermark" aria-label="Permalink to &quot;10. Watermark&quot;">​</a></h2><p>机制：表示已处理的源位置/事件时间进度。</p><p>实际用途：恢复、延迟和窗口完成。</p><p>失败方式：只用墙钟推断完整性。</p><p>验证：按partition记录并检测gap。</p><p>取舍：提供进度但需持久一致。</p><p>CDC watermark 应明确它表示已读取、已写入还是已对账的源日志位置，并按源分片持久化。只有该位置之前的更新与删除都已幂等落入目标，才能用它计算复制延迟或作为安全回填边界。</p><h2 id="_11-backfill" tabindex="-1">11. Backfill <a class="header-anchor" href="#_11-backfill" aria-label="Permalink to &quot;11. Backfill&quot;">​</a></h2><p>机制：历史数据按稳定分片重算。</p><p>实际用途：修复逻辑和新增指标。</p><p>失败方式：与增量双写无水位导致重复漏失。</p><p>验证：batch ID、版本、对账、限速。</p><p>取舍：可修复但资源和合并复杂。</p><p>Backfill 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要能力</th><th>边界</th></tr></thead><tbody><tr><td>OLTP行存</td><td>点查事务</td><td>大扫描干扰</td></tr><tr><td>列式OLAP</td><td>聚合扫描</td><td>逐行更新成本</td></tr><tr><td>ETL</td><td>目标前转换</td><td>原始重算能力弱</td></tr><tr><td>ELT</td><td>目标内转换</td><td>成本治理复杂</td></tr><tr><td>CDC</td><td>低延迟增量</td><td>不是完整备份</td></tr></tbody></table><h2 id="_13-完整案例-postgresql到clickhouse实时订单分析" tabindex="-1">13. 完整案例：PostgreSQL到ClickHouse实时订单分析 <a class="header-anchor" href="#_13-完整案例-postgresql到clickhouse实时订单分析" aria-label="Permalink to &quot;13. 完整案例：PostgreSQL到ClickHouse实时订单分析&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>订单主库不可被BI拖慢；分析5分钟内可见；删除和金额版本必须正确。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>PostgreSQL事务写事实并保留版本。</li><li>Debezium一致快照记录LSN后读取WAL。</li><li>Kafka按表/订单key传递，schema受控。</li><li>ClickHouse staging幂等写入并用版本模型生成查询表。</li><li>按tenant/day对账count、sum、max version与delete。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>交易主库承担正确性，ClickHouse承担扫描聚合，freshness可量化。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>snapshot+stream无gap；乱序最终最高版本；主库BI连接被禁止/限额。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>把更新当普通append会重复金额；必须保留变更语义并按版本构建事实。</p><h3 id="恢复与重跑" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>从已确认的源 LSN 与消费 offset 恢复，重复变更按订单主键和源版本幂等合并。若 ClickHouse 写入已成功但 offset 未提交，允许重放而不能重复计量；快照重建写入新表并持续追平 WAL，按 count、金额、删除和最大版本对账后再切换查询。</p><h2 id="_14-完整案例-批量财务etl" tabindex="-1">14. 完整案例：批量财务ETL <a class="header-anchor" href="#_14-完整案例-批量财务etl" aria-label="Permalink to &quot;14. 完整案例：批量财务ETL&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>每日对象存储CSV、金额需精确、错误行不能静默丢，次日8点报表。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>保存原始对象checksum和manifest。</li><li>解析到隔离staging，金额用decimal/整数分。</li><li>质量规则输出accepted/rejected与reason。</li><li>单batch事务/分区发布curated表。</li><li>对账文件总额、行数、重复业务键并记录lineage。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>每个报表可追溯到输入对象、代码版本和质量结果。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>重复运行同batch幂等；坏行有隔离；总额守恒。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>解析失败后跳过行仍显示job成功会少计；质量阈值和发布门禁必须阻止。</p><h3 id="恢复与重跑-1" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑-1" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>同一输入 manifest/checksum 生成稳定 batch ID，解析结果写该批次的隔离分区。失败重跑先清理或覆盖未发布分区，不触碰已审批报表；坏行修正规则产生新 run 与质量报告，总额和行数重新守恒后才原子替换该业务日版本。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期信号与恢复</th><th>禁止结果</th></tr></thead><tbody><tr><td>重复输入</td><td><code>oltp_p99</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>乱序和迟到</td><td><code>olap_scan_bytes</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>源schema变化</td><td><code>cdc_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>任务中途崩溃</td><td><code>snapshot_progress</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>下游429/503</td><td><code>schema_errors</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>checkpoint损坏</td><td><code>delete_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>质量规则失败</td><td><code>backfill_rate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>回填与实时并发</td><td><code>quality_reject</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>权限撤销</td><td><code>reconciliation_diff</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>成本超预算</td><td><code>pipeline_cost</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr></tbody></table><h2 id="_16-数据质量与对账" tabindex="-1">16. 数据质量与对账 <a class="header-anchor" href="#_16-数据质量与对账" aria-label="Permalink to &quot;16. 数据质量与对账&quot;">​</a></h2><ol><li>对每个源表记录快照起止 LSN、流起点和当前确认 LSN，证明 snapshot 与 stream 无 gap、无重叠漏算。</li><li>按 tenant/day 比较源端与目标端存活主键数；append-only 事件表另比较事件 ID 去重前后数量。</li><li>金额和数量使用源端可复算的整数或 decimal 聚合对账，任何非零财务差异阻断发布。</li><li>必填字段按 schema 版本检查；新增列在回填完成前允许的 null 范围必须显式限定到旧版本数据。</li><li>更新表比较每个分片的最大源版本与目标版本，并抽查同一主键的最终字段 hash。</li><li>删除单独统计源 delete、传输 tombstone、目标失效行；删除延迟超过合规窗口立即告警。</li><li>CDC freshness 同时报“当前时间减源 commit time”和“最新已处理 LSN”，避免无新写入时误判。</li><li>schema 变更先验证主键、类型兼容和默认值；无法解析的事件进入隔离 topic，不能跳过并推进确认位点。</li><li>回填与实时流按主键版本仲裁，检查旧回填不会覆盖更高版本的在线变更。</li><li>每日固定抽样主键，从 OLTP 当前行、变更日志到 OLAP 最终行逐字段核验并保存差异证据。</li></ol><h2 id="_17-调试与观测" tabindex="-1">17. 调试与观测 <a class="header-anchor" href="#_17-调试与观测" aria-label="Permalink to &quot;17. 调试与观测&quot;">​</a></h2><ol><li><code>oltp_p99</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>olap_scan_bytes</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>cdc_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>snapshot_progress</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>schema_errors</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>delete_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>backfill_rate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>quality_reject</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>reconciliation_diff</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>pipeline_cost</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li></ol><p>CDC 排障选择一个订单主键和时间区间，依次核对源行版本、WAL/LSN、Debezium envelope、Kafka partition/offset、目标 staging 版本与最终查询行；批 ETL 则从对象 checksum、rejected 清单、发布分区追到报表 SQL。连接器 running 或 DAG success 都不能替代端到端对账。</p><h2 id="_18-安全、成本与运维边界" tabindex="-1">18. 安全、成本与运维边界 <a class="header-anchor" href="#_18-安全、成本与运维边界" aria-label="Permalink to &quot;18. 安全、成本与运维边界&quot;">​</a></h2><ol><li>源凭据最小权限；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>PII分层访问和脱敏；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>原始层不可被普通BI任意下载；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>重跑/回填有资源配额；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>流批共享sink有容量仲裁；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>删除请求传播到派生层；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>schema发布兼容门禁；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>checkpoint/manifest备份；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>灾备恢复演练；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>成本按pipeline/dataset/tenant归集；OLTP、OLAP、ETL、ELT 与 CDC 的实现要提供owner、runbook、停止阈值和审计记录。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“PostgreSQL到ClickHouse实时订单分析”，再以“批量财务ETL”验证另一类时效/治理约束。提交数据样例、模型、质量测试、故障注入、lineage和成本面板。</p><ul><li>[ ] OLTP 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] OLAP 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] ETL 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] ELT 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] CDC 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Snapshot 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Delete/Tombstone 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Schema evolution 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] 两个案例包含输入、步骤、输出、验证、失败与重跑。</li><li>[ ] 源与目标按业务分片完成count/sum/version/hash对账。</li><li>[ ] 历史发布版本可回退，回填不压垮在线事实系统。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.postgresql.org/docs/18/logicaldecoding.html" target="_blank" rel="noreferrer">PostgreSQL 18 logical decoding</a>（访问日期：2026-07-17）</li><li><a href="https://debezium.io/documentation/reference/stable/connectors/postgresql.html" target="_blank" rel="noreferrer">Debezium PostgreSQL connector</a>（访问日期：2026-07-17）</li><li><a href="https://clickhouse.com/docs/architecture/introduction" target="_blank" rel="noreferrer">ClickHouse architecture</a>（访问日期：2026-07-17）</li><li><a href="https://kafka.apache.org/documentation/" target="_blank" rel="noreferrer">Apache Kafka 4.3 documentation</a>（访问日期：2026-07-17）</li><li><a href="https://docs.getdbt.com/docs/introduction" target="_blank" rel="noreferrer">dbt docs</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const b=e(i,[["render",r]]);export{u as __pageData,b as default};
